// ── Voice Selection by Section Role ───────────────────────────────────────────
// Different section types call for different emotional registers.
// Problem sections earn trust through vulnerability + empathy.
// Insight sections use enthusiasm and skepticism → conviction arc.
// Contrarian sections use conviction + frustration (at the conventional approach).
// Action sections use empathy + asides (practical, grounded).
// Depth sections use self-correction + vulnerability (honest complexity).

export type VoiceType = keyof typeof VOICE;

export function pickVoice(category: VoiceType, index: number): string {
  const pool = VOICE[category];
  return pool[Math.abs(index) % pool.length] ?? "";
}

export function pickVoiceBlend(primary: VoiceType, secondary: VoiceType, index: number): string {
  // Returns primary for even indices, secondary for odd — creating natural variation
  return index % 2 === 0 ? pickVoice(primary, index) : pickVoice(secondary, index);
}
